"use client";

import { useState, useEffect, useCallback } from "react";
import dynamic from "next/dynamic";
import Header from "@/components/Header";
import CaseProfile from "@/components/CaseProfile";
import RightSidebar from "@/components/RightSidebar";
import BottomBar from "@/components/BottomBar";
import { INITIAL_CASES, INITIAL_CHAT, INITIAL_FEED, INITIAL_STATS, Case } from "@/lib/data";
import { getLatestReports, ReliefWebReport } from "@/lib/liveData";
import { Plus, Share2 } from "lucide-react";

// Dynamic import for Leaflet to avoid SSR issues
const Map = dynamic(() => import("@/components/Map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-background flex items-center justify-center font-mono text-primary animate-pulse">LOADING GLOBAL MAP SYSTEM...</div>
});

export default function Dashboard() {
  const [cases, setCases] = useState(INITIAL_CASES);
  const [chat, setChat] = useState(INITIAL_CHAT);
  const [feed, setFeed] = useState(INITIAL_FEED);
  const [stats, setStats] = useState(INITIAL_STATS);
  const [selectedCaseId, setSelectedCaseId] = useState<string | null>("case-5");
  const [reports, setReports] = useState<ReliefWebReport[]>([]);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());

  const fetchReports = useCallback(async () => {
    const latestReports = await getLatestReports();
    setReports(latestReports);
    setLastUpdated(new Date());
  }, []);

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    fetchReports();
    const interval = setInterval(fetchReports, 60000);
    return () => clearInterval(interval);
  }, [fetchReports]);

  const selectedCase = cases.find(c => c.id === selectedCaseId) || null;

  // Simulate periodic updates
  useEffect(() => {
    const interval = setInterval(() => {
      // Add random chat message
      const users = ["void_walker", "hanta_believer", "istthatmystic", "elibedovic7774", "cryptoguard"];
      const messages = [
        "Did you see the new markers in Germany?",
        "CFR rate is climbing. This is not good.",
        "Anyone in Zurich? Stay indoors.",
        "The ship group was larger than they said.",
        "Check the source feed, Heathrow is locking down.",
      ];

      const newUser = users[Math.floor(Math.random() * users.length)];
      const newMessage = messages[Math.floor(Math.random() * messages.length)];

      setChat(prev => [...prev.slice(-15), {
        id: Date.now(),
        user: newUser,
        message: newMessage,
        timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
      }]);

      // Slowly increment stats
      setStats(prev => ({
        ...prev,
        total: prev.total + Math.floor(Math.random() * 3),
        suspected: prev.suspected + Math.floor(Math.random() * 2),
      }));

      // Add random alert to feed
      if (Math.random() > 0.4) {
        const alerts = [
          "HEATHROW AIRPORT LOCKDOWN INITIATED",
          "NEW CLUSTER DETECTED IN MARSEILLE",
          "WHO DECLARES LEVEL 4 EMERGENCY",
          "PORT OF ROTTERDAM QUARANTINE PROTOCOL",
          "VACCINE RESEARCH FACILITY BREACH REPORTED",
          "ZURICH QUARANTINE ZONE EXPANDED",
          "BERLIN SECTOR 7 CLEARANCE REVOKED",
          "NUCLEAR POWER PLANT SCRAMMED - CONTAINMENT FAILURE",
          "INTERPOL ISSUES RED NOTICE FOR PATIENT ZERO",
          "SATELLITE THERMAL SCAN: UNKNOWN HEAT SIGNATURES IN ALPS"
        ];
        const newAlert = alerts[Math.floor(Math.random() * alerts.length)];
        setFeed(prev => [{
          id: Date.now(),
          type: Math.random() > 0.6 ? "CRITICAL" : "WARNING",
          text: newAlert,
          timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
        }, ...prev.slice(0, 15)]);
      }
    }, 6000); // Faster updates for "live" feel

    return () => clearInterval(interval);
  }, []);

  const simulateNewCase = useCallback(() => {
    const locations = [
      { name: "MUNICH, DE", lat: 48.1351, lng: 11.582 },
      { name: "LYON, FR", lat: 45.764, lng: 4.8357 },
      { name: "VIENNA, AT", lat: 48.2082, lng: 16.3738 },
      { name: "MILAN, IT", lat: 45.4642, lng: 9.1899 },
    ];

    const loc = locations[Math.floor(Math.random() * locations.length)];
    const id = `case-${Date.now()}`;
    const newCase: Case = {
      id,
      number: cases.length + 1,
      location: loc.name,
      lat: loc.lat + (Math.random() - 0.5) * 0.1,
      lng: loc.lng + (Math.random() - 0.5) * 0.1,
      status: Math.random() > 0.7 ? "CONFIRMED" : "SUSPECTED",
      details: "New cluster detected via thermal screening. Investigation ongoing.",
      sex: Math.random() > 0.5 ? "MALE" : "FEMALE",
      age: Math.floor(Math.random() * 40) + 20,
      ship: "MV HONDIUS (SECONDARY)",
      source: "LOCAL-HEALTH-AUTH",
      coordinates: `${loc.lat.toFixed(2)}°N ${loc.lng.toFixed(2)}°E`,
      timestamp: new Date().toISOString(),
    };

    setCases(prev => [...prev, newCase]);
    setFeed(prev => [{
      id: Date.now(),
      type: "ALERT",
      text: `NEW CLUSTER DETECTED: ${loc.name}`,
      timestamp: "Just now"
    }, ...prev.slice(0, 9)]);

    setStats(prev => ({
      ...prev,
      total: prev.total + 1,
      suspected: prev.suspected + 1,
      locations: prev.locations + 1
    }));
  }, [cases.length]);

  const handleSendMessage = useCallback((message: string) => {
    setChat(prev => [...prev.slice(-15), {
      id: Date.now(),
      user: "YOU",
      message,
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    }]);
  }, []);

  const handleSelectLocation = useCallback((locationName: string) => {
    // Find the first case with this location or just fallback to Zurich if none found
    const found = cases.find(c => c.location.includes(locationName.split(',')[0]));
    if (found) {
      setSelectedCaseId(found.id);
    }
  }, [cases]);

  const [isFlashing, setIsFlashing] = useState(false);

  const handleShareScreenshot = async () => {
    setIsFlashing(true);

    // Add temporary class to hide elements
    const hideElements = document.querySelectorAll(".screenshot-hide");
    hideElements.forEach(el => el.classList.add("hidden"));

    setTimeout(async () => {
      try {
        const dashboard = document.querySelector("main");
        if (dashboard) {
          const { toPng } = await import("html-to-image");

          const dataUrl = await toPng(dashboard, {
            backgroundColor: "#0a0f0a",
            quality: 1,
            pixelRatio: 2,
            cacheBust: true,
            filter: (node) => {
              const element = node as HTMLElement;
              if (element.classList) {
                return !element.classList.contains('screenshot-hide') && !element.classList.contains('animate-flash');
              }
              return true;
            }
          });

          const link = document.createElement("a");
          link.href = dataUrl;
          link.download = `HANTA-GLOBAL-INTEL-${new Date().getTime()}.png`;
          link.click();
        }
      } catch (err) {
        console.error("Screenshot failed:", err);
      } finally {
        hideElements.forEach(el => el.classList.remove("hidden"));
        setIsFlashing(false);
      }
    }, 200);
  };

  return (
    <main className="h-screen w-screen flex flex-col bg-background text-primary selection:bg-primary selection:text-background overflow-hidden relative">
      {/* Flash Effect Layer */}
      {isFlashing && <div className="absolute inset-0 z-[9999] animate-flash pointer-events-none" />}

      <Header stats={stats} lastUpdated={lastUpdated} />

      <div className="flex-1 flex min-h-0 relative">
        <CaseProfile selectedCase={selectedCase} />

        <div className="flex-1 relative flex flex-col min-w-0">
          <Map 
            cases={cases} 
            selectedCaseId={selectedCaseId} 
            onSelectCase={setSelectedCaseId} 
          />

          {/* Simulation Overlay (Hidden on Screenshot) */}
          <div className="absolute top-6 right-6 z-[1000] flex flex-col space-y-3 screenshot-hide">
            <button 
              onClick={simulateNewCase}
              className="flex items-center space-x-2 bg-background/80 hover:bg-primary/20 border border-primary/40 px-4 py-2 rounded font-mono text-xs text-primary transition-all glow-border-green group shadow-[0_0_15px_rgba(0,255,159,0.1)]"
            >
              <Plus size={14} className="group-hover:rotate-90 transition-transform" />
              <span>SIMULATE NEW CASE</span>
            </button>

            <button 
              className="flex items-center space-x-2 bg-secondary/10 hover:bg-secondary/20 border border-secondary/40 px-4 py-2 rounded font-mono text-xs text-secondary transition-all shadow-[0_0_15px_rgba(255,0,170,0.1)] group relative overflow-hidden"
              onClick={handleShareScreenshot}
            >
              <div className="absolute inset-0 bg-secondary/5 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-1000 ease-in-out pointer-events-none" />
              <Share2 size={14} className="group-hover:rotate-12 transition-transform" />
              <span className="opacity-70 group-hover:opacity-100 uppercase font-black tracking-widest text-[10px]">Capture Intel</span>
            </button>
          </div>
        </div>

        <RightSidebar 
          messages={chat} 
          onSendMessage={handleSendMessage}
          onSelectLocation={handleSelectLocation}
        />
      </div>

      <BottomBar feed={feed} reports={reports} />

      {/* Grid Overlay for aesthetic */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.03] z-[100]" 
           style={{ backgroundImage: 'radial-gradient(#00ff9f 1px, transparent 0)', backgroundSize: '40px 40px' }} />
    </main>
  );
}

@import "tailwindcss";

@theme {
  --color-background: #0a0f0a;
  --color-foreground: #00ff9f;
  --color-primary: #00ff9f;
  --color-secondary: #ff00aa;
  --color-accent: #ff8c00;
  --color-deceased: #ff4d4d;
  --color-confirmed: #ff8c00;
  --color-suspected: #ffea00;
  --color-monitoring: #00ff9f;

  --font-mono: var(--font-vt323), monospace;
}

@layer base {
  :root {
    --background: #0a0f0a;
    --foreground: #00ff9f;
  }

  body {
    background-color: var(--background);
    color: var(--foreground);
    font-family: var(--font-sans);
    overflow: hidden;
  }
}

@layer utilities {
  .glow-green {
    text-shadow: 0 0 10px #00ff9f, 0 0 20px #00ff9f;
  }
  .glow-pink {
    text-shadow: 0 0 10px #ff00aa, 0 0 20px #ff00aa;
  }
  .glow-border-green {
    box-shadow: 0 0 10px #00ff9f, inset 0 0 5px #00ff9f;
    border: 1px solid #00ff9f;
  }
  .glow-border-pink {
    box-shadow: 0 0 10px #ff00aa, inset 0 0 5px #ff00aa;
    border: 1px solid #ff00aa;
  }
  .bg-glass {
    background-color: rgba(10, 15, 10, 0.8);
    backdrop-filter: blur(8px);
    border: 1px solid rgba(0, 255, 159, 0.2);
  }
}

/* MapLibre & Tactical HUD Styles */
.map-container {
  width: 100%;
  height: 100%;
  background: #000 !important;
}

.maplibregl-canvas {
  outline: none;
}

/* Custom Tactical Popup */
.maplibregl-popup-content {
  background: rgba(10, 15, 10, 0.9) !important;
  color: #00ff9f !important;
  border: 1px solid rgba(0, 255, 159, 0.5) !important;
  border-radius: 0 !important;
  padding: 12px !important;
  backdrop-filter: blur(10px);
  box-shadow: 0 0 20px rgba(0, 255, 159, 0.2) !important;
  font-family: var(--font-mono) !important;
}

.maplibregl-popup-tip {
  border-top-color: rgba(0, 255, 159, 0.5) !important;
}

/* Pulsing Marker Animations */
@keyframes pulse-ring {
  0% { transform: translate(-50%, -50%) scale(0.3); opacity: 0.8; }
  100% { transform: translate(-50%, -50%) scale(1.2); opacity: 0; }
}

@keyframes ring-pulse-1 {
  0% { transform: scale(1); opacity: 0.8; }
  100% { transform: scale(2.5); opacity: 0; }
}

@keyframes ring-pulse-2 {
  0% { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(3.5); opacity: 0; }
}

@keyframes ring-pulse-3 {
  0% { transform: scale(1); opacity: 0.4; }
  100% { transform: scale(4.5); opacity: 0; }
}

.animate-ring-1 { animation: ring-pulse-1 2s cubic-bezier(0, 0, 0.2, 1) infinite; }
.animate-ring-2 { animation: ring-pulse-2 2s cubic-bezier(0, 0, 0.2, 1) infinite 0.5s; }
.animate-ring-3 { animation: ring-pulse-3 2s cubic-bezier(0, 0, 0.2, 1) infinite 1s; }

/* CRT Scanline Effect */
.crt-overlay {
  position: fixed;
  inset: 0;
  background: linear-gradient(
    rgba(18, 16, 16, 0) 50%, 
    rgba(0, 0, 0, 0.1) 50%
  ), 
  linear-gradient(90deg, 
    rgba(255, 0, 0, 0.02), 
    rgba(0, 255, 0, 0.01), 
    rgba(0, 0, 255, 0.02)
  );
  background-size: 100% 3px, 3px 100%;
  pointer-events: none;
  z-index: 9999;
  opacity: 0.15;
}

.crt-overlay::before {
  content: " ";
  display: block;
  position: absolute;
  inset: 0;
  background: linear-gradient(rgba(18, 16, 16, 0) 0%, rgba(32, 255, 128, 0.02) 50%, rgba(18, 16, 16, 0) 100%);
  background-size: 100% 200%;
  animation: scanline-scroll 8s linear infinite;
  pointer-events: none;
}

@keyframes scanline-scroll {
  0% { background-position: 0 -100%; }
  100% { background-position: 0 100%; }
}

@keyframes flicker {
  0% { opacity: 0.27; }
  5% { opacity: 0.35; }
  10% { opacity: 0.23; }
  15% { opacity: 0.90; }
  20% { opacity: 0.18; }
  25% { opacity: 0.83; }
  30% { opacity: 0.65; }
  35% { opacity: 0.57; }
  40% { opacity: 0.26; }
  100% { opacity: 0.12; }
}

.crt-flicker {
  animation: flicker 0.15s infinite;
}

/* Marquee Animation */
.animate-marquee {
  display: flex;
  width: max-content;
  animation: marquee 40s linear infinite;
}

@keyframes marquee {
  0% { transform: translateX(0); }
  100% { transform: translateX(-50%); }
}

@keyframes shimmer {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(100%); }
}

.animate-shimmer {
  animation: shimmer 2s infinite;
}

@keyframes pulse-subtle {
  0% { opacity: 0.15; }
  50% { opacity: 0.35; }
  100% { opacity: 0.15; }
}

.animate-pulse-subtle {
  animation: pulse-subtle 4s ease-in-out infinite;
}

@keyframes glow-pulse {
  0% { filter: drop-shadow(0 0 5px #00ff9f); }
  50% { filter: drop-shadow(0 0 15px #00ff9f); }
  100% { filter: drop-shadow(0 0 5px #00ff9f); }
}

.animate-glow-pulse {
  animation: glow-pulse 3s infinite;
}

/* Flash Effect for Screenshot */
@keyframes flash {
  0% { background-color: rgba(255, 255, 255, 0); }
  10% { background-color: rgba(255, 255, 255, 0.8); }
  100% { background-color: rgba(255, 255, 255, 0); }
}

.animate-flash {
  animation: flash 0.5s ease-out forwards;
}

/* Scan Line Animation */
@keyframes scan-line-movement {
  0% { transform: translateY(-100vh); }
  100% { transform: translateY(100vh); }
}

.animate-scan-line {
  animation: scan-line-movement 6s linear infinite;
}

/* Custom Scrollbar */
::-webkit-scrollbar {
  width: 4px;
  height: 4px;
}
::-webkit-scrollbar-track {
  background: #0a0f0a;
}
::-webkit-scrollbar-thumb {
  background: #00ff9f;
  border-radius: 2px;
}
::-webkit-scrollbar-thumb:hover {
  background: #ff00aa;
}

/* Panel & Utility Styles */
.glass-panel {
  background: rgba(10, 15, 10, 0.4) !important;
  backdrop-filter: blur(20px) saturate(180%);
}

.animate-pulse-gentle {
  animation: pulse-gentle 3s infinite ease-in-out;
}

@keyframes pulse-gentle {
  0% { opacity: 0.8; transform: scale(1); }
  50% { opacity: 1; transform: scale(1.02); }
  100% { opacity: 0.8; transform: scale(1); }
}

.vignette {
  position: absolute;
  inset: 0;
  background: radial-gradient(circle, transparent 40%, rgba(0,0,0,0.8) 100%);
  pointer-events: none;
  z-index: 99;
}

.map-grid-overlay {
  background-image: 
    linear-gradient(rgba(0, 255, 159, 0.05) 1px, transparent 1px),
    linear-gradient(90deg, rgba(0, 255, 159, 0.05) 1px, transparent 1px);
  background-size: 50px 50px;
  pointer-events: none;
}

@media (max-width: 1024px) {
  .sidebar-hide {
    display: none;
  }
}

"use client";

import React, { useEffect, useRef, useState } from "react";
import Map, { MapRef, NavigationControl, Marker, Popup, Source, Layer } from "react-map-gl/maplibre";
import "maplibre-gl/dist/maplibre-gl.css";
import { Case } from "@/lib/data";
import { generateOutbreakArcs } from "@/lib/arcUtils";
import { cn } from "@/lib/utils";

interface TacticalMapProps {
  cases: Case[];
  selectedCaseId: string | null;
  onSelectCase: (id: string) => void;
}

const WORLD_GEOJSON = "https://raw.githubusercontent.com/datasets/geo-countries/master/data/countries.geojson";

export default function TacticalMap({ cases, selectedCaseId, onSelectCase }: TacticalMapProps) {
  const mapRef = useRef<MapRef>(null);
  const [mounted, setMounted] = useState(false);
  const [viewport, setViewport] = useState({
    latitude: 0,
    longitude: 0,
    zoom: 1.5,
    pitch: 0,
    bearing: 0
  });

  const [popupInfo, setPopupInfo] = useState<Case | null>(null);
  const [autoRotate, setAutoRotate] = useState(true); // Enabled by default
  const [liveScan, setLiveScan] = useState(true); // Automated surveillance mode
  const [focusedCaseId, setFocusedCaseId] = useState<string | null>(null);
  const rotationRef = useRef<number>(0);
  const lastInteractionRef = useRef<number>(Date.now());
  const scanTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    // eslint-disable-next-line react-hooks/set-state-in-effect
    setMounted(true);
  }, []);

  // Auto-Rotation Logic
  useEffect(() => {
    const interval = setInterval(() => {
      const now = Date.now();
      const idleTime = now - lastInteractionRef.current;

      // Only rotate if autoRotate is ON and we're NOT in the middle of a focused fly-to
      if (autoRotate && idleTime > 10000 && !focusedCaseId) { 
        setViewport(prev => ({
          ...prev,
          longitude: (prev.longitude + 0.05) % 360 
        }));
      }
    }, 50);

    return () => clearInterval(interval);
  }, [autoRotate, focusedCaseId]);

  // Live Scan Mode Logic (Intelligent Surveillance)
  useEffect(() => {
    if (!liveScan) return;

    const runScan = () => {
      const now = Date.now();
      const idleTime = now - lastInteractionRef.current;

      // Pause if user interacted recently
      if (idleTime < 20000) {
        scanTimeoutRef.current = setTimeout(runScan, 5000);
        return;
      }

      if (mapRef.current && liveScan) {
        // Weighted selection: Zurich, Berlin, London, Amsterdam are higher priority
        const weightedPool = cases.flatMap(c => {
          const isHighPriority = c.location.includes("ZURICH") || 
                                 c.location.includes("BERLIN") || 
                                 c.location.includes("LONDON") || 
                                 c.location.includes("AMSTERDAM");
          return Array(isHighPriority ? 5 : 1).fill(c);
        });

        const target = weightedPool[Math.floor(Math.random() * weightedPool.length)];

        // Focus on location
        setFocusedCaseId(target.id);
        mapRef.current.flyTo({
          center: [target.lng, target.lat],
          zoom: 6,
          pitch: 45,
          bearing: Math.random() * 30 - 15,
          duration: 4000,
          essential: true
        });

        // Hold for 8s then release
        scanTimeoutRef.current = setTimeout(() => {
          setFocusedCaseId(null);
          if (mapRef.current) {
            mapRef.current.easeTo({
              zoom: 1.5,
              pitch: 0,
              duration: 4000
            });
          }
          // Schedule next scan in 18-35 seconds
          const nextInterval = Math.random() * (35000 - 18000) + 18000;
          scanTimeoutRef.current = setTimeout(runScan, nextInterval);
        }, 8000);
      }
    };

    // Initial delay
    const initialDelay = Math.random() * 10000 + 5000;
    scanTimeoutRef.current = setTimeout(runScan, initialDelay);

    return () => {
      if (scanTimeoutRef.current) clearTimeout(scanTimeoutRef.current);
    };
  }, [liveScan, cases]);

  useEffect(() => {
    if (selectedCaseId && mapRef.current) {
      const selected = cases.find((c) => c.id === selectedCaseId);
      if (selected) {
        mapRef.current.flyTo({
          center: [selected.lng, selected.lat],
          zoom: 7,
          duration: 2000,
          essential: true,
          pitch: 45,
          bearing: Math.random() * 20 - 10,
        });
        setPopupInfo(selected);
        lastInteractionRef.current = Date.now(); // Mark interaction
      }
    }
  }, [selectedCaseId, cases]);

  // Set atmosphere/fog for the globe
  useEffect(() => {
    if (mapRef.current) {
      const map = mapRef.current.getMap() as any;
      const updateFog = () => {
        if (typeof map.setFog === 'function') {
          map.setFog({
          color: 'rgb(0, 10, 5)', // Deep space with a hint of green
          'high-color': 'rgba(0, 255, 159, 0.7)', // Stronger neon horizon
          'horizon-blend': 0.1,
          'space-color': 'rgb(5, 0, 5)', // Subtle magenta hint in space
          'star-intensity': 0.8,
          'star-color': 'rgba(255, 0, 170, 0.5)' // Pink stars for contrast
          });
        }
      };

      if (map.isStyleLoaded()) updateFog();
      else map.on('style.load', updateFog);
    }
  }, [mounted]);


  const handleZoom = (delta: number) => {
    if (mapRef.current) {
      const currentZoom = mapRef.current.getZoom();
      mapRef.current.zoomTo(currentZoom + delta, { duration: 500 });
      lastInteractionRef.current = Date.now();
    }
  };

  const handleRotate = (delta: number) => {
    if (mapRef.current) {
      const currentBearing = mapRef.current.getBearing();
      mapRef.current.rotateTo(currentBearing + delta, { duration: 500 });
      lastInteractionRef.current = Date.now();
    }
  };

  const handleEuropeFocus = () => {
    if (mapRef.current) {
      mapRef.current.flyTo({
        center: [15, 50],
        zoom: 3.5,
        pitch: 30,
        duration: 3000
      });
      lastInteractionRef.current = Date.now();
    }
  };

  const handleWorldView = () => {
    if (mapRef.current) {
      mapRef.current.flyTo({
        center: [0, 0],
        zoom: 1.5,
        pitch: 0,
        duration: 3000
      });
      lastInteractionRef.current = Date.now();
    }
  };

  if (!mounted) return null;

  return (
    <div className="w-full h-full relative bg-black overflow-hidden" id="tactical-map-container">
      <Map
        ref={mapRef}
        initialViewState={viewport}
        onMove={(evt) => {
          setViewport(evt.viewState);
        }}
        onDragStart={() => lastInteractionRef.current = Date.now()}
        onZoomStart={() => lastInteractionRef.current = Date.now()}
        onMoveStart={() => lastInteractionRef.current = Date.now()}
        mapStyle="https://basemaps.cartocdn.com/gl/dark-matter-gl-style/style.json"
        style={{ width: "100%", height: "100%" }}
        projection="globe"
        {...({ preserveDrawingBuffer: true } as any)}
        dragRotate={true}
        touchPitch={true}
        touchZoomRotate={true}
      >
        <NavigationControl position="top-right" />
        {/* Country Borders & Glow Layers */}
        <Source id="countries" type="geojson" data={WORLD_GEOJSON}>
          {/* High Density Country Pulse (CH, NL, DE, FR) */}
          <Layer
            id="high-density-glow"
            type="fill"
            filter={['in', ['get', 'iso_a2'], ['literal', ['CH', 'NL', 'DE', 'FR']]]}
            paint={{
              "fill-color": "#00ff9f",
              "fill-opacity": ["interpolate", ["linear"], ["zoom"], 0, 0.1, 5, 0.2], // Deeper on zoom
              "fill-outline-color": "#00ff9f",
            }}
          />
          {/* Animated Country Pulse (Simulated via overlay) */}
          <Layer
            id="high-density-pulse"
            type="fill"
            filter={['in', ['get', 'iso_a2'], ['literal', ['CH', 'NL', 'DE', 'FR']]]}
            paint={{
              "fill-color": "#00ff9f",
              "fill-opacity": 0.05,
            }}
          />
          <Layer
            id="country-glow-outer"
            type="line"
            paint={{
              "line-color": "#00ff9f",
              "line-width": 10,
              "line-blur": 8,
              "line-opacity": 0.3
            }}
          />
          <Layer
            id="country-core"
            type="line"
            paint={{
              "line-color": "#00ff9f",
              "line-width": 1,
              "line-opacity": 0.5
            }}
          />
        </Source>

        <Source id="outbreak-arcs" type="geojson" data={generateOutbreakArcs(cases)}>
          <Layer
            id="arc-glow"
            type="line"
            paint={{
              "line-color": [
                "match",
                ["get", "status"],
                "DECEASED", "#ff4d4d",
                "CONFIRMED", "#ff00aa",
                "#00ff9f"
              ],
              "line-width": 8,
              "line-blur": 5,
              "line-opacity": 0.2
            }}
          />
          <Layer
            id="arc-core"
            type="line"
            paint={{
              "line-color": [
                "match",
                ["get", "status"],
                "DECEASED", "#ff4d4d",
                "CONFIRMED", "#ff00aa",
                "#00ff9f"
              ],
              "line-width": 1.5,
              "line-opacity": 0.6
            }}
          />
        </Source>

        {/* Tactical Markers */}
        {cases.map((c) => {
          const isMajor = c.location.includes("ZURICH") || c.location.includes("BERLIN");
          return (
            <Marker 
              key={c.id} 
              longitude={c.lng} 
              latitude={c.lat} 
              anchor="center"
            >
              <div 
                className={cn(
                  "relative group cursor-pointer transition-all duration-1000",
                  focusedCaseId === c.id ? "scale-150" : "scale-100"
                )}
                onClick={(e) => {
                  e.stopPropagation();
                  onSelectCase(c.id);
                  setPopupInfo(c);
                  lastInteractionRef.current = Date.now();
                }}
              >
                {/* Concentric Pulsing Rings (Elite Upgrade) */}
                <div className={cn(
                  "absolute -inset-8 rounded-full border-2 border-current opacity-0 animate-ring-1",
                  isMajor ? "scale-150" : "",
                  c.status === 'CONFIRMED' ? 'text-secondary' : 
                  c.status === 'DECEASED' ? 'text-red-500' : 'text-primary'
                )} style={{ animationDelay: '0s' }} />
                <div className={cn(
                  "absolute -inset-12 rounded-full border border-current opacity-0 animate-ring-2",
                  isMajor ? "scale-150" : "",
                  c.status === 'CONFIRMED' ? 'text-secondary' : 
                  c.status === 'DECEASED' ? 'text-red-500' : 'text-primary'
                )} style={{ animationDelay: '0.5s' }} />
                <div className={cn(
                  "absolute -inset-16 rounded-full border border-current opacity-0 animate-ring-3",
                  isMajor ? "scale-150" : "",
                  c.status === 'CONFIRMED' ? 'text-secondary' : 
                  c.status === 'DECEASED' ? 'text-red-500' : 'text-primary'
                )} style={{ animationDelay: '1s' }} />

                {/* Focus Ring (Live Scan Mode) */}
                {focusedCaseId === c.id && (
                  <div className="absolute -inset-24 rounded-full border-4 border-primary opacity-40 animate-ping shadow-[0_0_50px_#00ff9f]" />
                )}
                <div className={cn(
                  "w-4 h-4 rounded-full border-2 border-white shadow-[0_0_20px_currentColor] relative z-10 transition-transform duration-300 group-hover:scale-150",
                  isMajor ? "w-6 h-6 border-4" : "",
                  c.status === 'CONFIRMED' ? 'bg-secondary text-secondary' : 
                  c.status === 'DECEASED' ? 'bg-red-500 text-red-500' : 'bg-primary text-primary'
                )} />

                {/* Tooltip on Hover */}
                <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 px-4 py-2 bg-black/95 backdrop-blur-xl border border-white/10 rounded-sm opacity-0 group-hover:opacity-100 transition-all pointer-events-none z-[200] shadow-[0_0_30px_rgba(0,0,0,1)] whitespace-nowrap border-b-2 border-b-primary scale-90 group-hover:scale-100 origin-bottom">
                  <div className="flex flex-col items-center">
                    <span className="font-mono text-[10px] font-black text-primary uppercase tracking-[0.2em]">{c.location}</span>
                    <div className="flex items-center space-x-2 mt-1">
                      <span className="font-mono text-[8px] font-black tracking-widest text-white/40">ID: {c.number.toString().padStart(3, '0')}</span>
                      <div className="w-1 h-1 rounded-full bg-white/20" />
                      <span className={cn(
                        "font-mono text-[8px] font-black tracking-widest",
                        c.status === 'CONFIRMED' ? 'text-secondary' : 'text-primary'
                      )}>{c.status}</span>
                    </div>
                  </div>
                </div>
              </div>
            </Marker>
          );
        })}

        {/* Selected Case Popup */}
        {popupInfo && (
          <Popup
            longitude={popupInfo.lng}
            latitude={popupInfo.lat}
            anchor="bottom"
            onClose={() => setPopupInfo(null)}
            closeButton={false}
            className="tactical-popup"
            offset={30}
          >
            <div className="min-w-[220px] p-3 font-mono bg-black/95 backdrop-blur-xl border border-primary/40 shadow-[0_0_50px_rgba(0,255,159,0.3)] rounded-sm">
