                <div className={`text-[9px] px-2 py-0.5 rounded font-black ${
                  popupInfo.status === 'CONFIRMED' ? 'bg-secondary text-black glow-pink' : 
                  popupInfo.status === 'DECEASED' ? 'bg-red-600 text-white' : 'bg-primary text-black'
